import React, { createContext, useContext, useState, useLayoutEffect, useMemo } from 'react';
import { themes } from '../styles/theme';

const ThemeContext = createContext();

// Helper to transform flat CSS custom properties into nested structure
const transformTheme = (flatTheme) => {
  if (!flatTheme) return {};
  
  return {
    colors: {
      primary: flatTheme['--accent-primary'] || '#10b981',
      secondary: flatTheme['--accent-secondary'] || '#059669',
      text: {
        main: flatTheme['--text-primary'] || '#ffffff',
        secondary: flatTheme['--text-secondary'] || 'rgba(255, 255, 255, 0.7)',
        muted: flatTheme['--text-muted'] || 'rgba(255, 255, 255, 0.4)',
      },
      background: {
        main: flatTheme['--bg-main'] || '#050505',
        secondary: flatTheme['--bg-secondary'] || '#0b0c10',
      },
      border: flatTheme['--surface-border'] || 'rgba(255, 255, 255, 0.08)',
    },
    fonts: {
      header: "'Inter', sans-serif",
      body: "'Inter', sans-serif",
    },
  };
};

export const ThemeProvider = ({ children }) => {
  const [mode, setMode] = useState(() => localStorage.getItem('finify-mode') || 'dark');

  useLayoutEffect(() => {
    const root = window.document.documentElement;
    const currentTheme = themes[mode];

    if (currentTheme) {
      Object.entries(currentTheme).forEach(([prop, val]) => {
        root.style.setProperty(prop, val);
      });
      root.setAttribute('data-theme', mode);
      localStorage.setItem('finify-mode', mode);
    }
  }, [mode]);

  const toggleTheme = () => setMode(prev => (prev === 'dark' ? 'light' : 'dark'));

  // Transform flat theme into nested structure for component use
  const theme = useMemo(() => transformTheme(themes[mode]), [mode]);

  return (
    <ThemeContext.Provider value={{ mode, isDarkMode: mode === 'dark', toggleTheme, theme }}>
      {children}
    </ThemeContext.Provider>
  );
};

export const useTheme = () => useContext(ThemeContext);
